import java.util.ArrayList;
import java.util.List;
import java.util.TreeMap;

public class Solution {
    public List<List<Integer>> splitPainting(int[][] segments) {
        TreeMap<Integer, Integer> changes = new TreeMap<>();
        for (int[] segment : segments) {
            changes.put(segment[0], changes.getOrDefault(segment[0], 0) + segment[2]);
            changes.put(segment[1], changes.getOrDefault(segment[1], 0) - segment[2]);
        }

        List<List<Integer>> result = new ArrayList<>();
        int start = 0, color_sum = 0;
        for (int key : changes.keySet()) {
            if (start != key) {
                if (color_sum != 0) {
                    List<Integer> temp = new ArrayList<>();
                    temp.add(start);
                    temp.add(key);
                    temp.add(color_sum);
                    result.add(temp);
                }
                start = key;
            }
            color_sum += changes.getOrDefault(key, 0);
        }

        return result;
    }
}
```

